import time

def sure_olc(func):
    def wrapper(*args, **kwargs):
        basla = time.time()
        sonuc = func(*args, **kwargs)
        bitis = time.time()
        print(f'{func.__name__} {bitis - basla:.4f} saniye surdu')
        return sonuc
    return wrapper

@sure_olc
def bekle():
    time.sleep(1)

bekle()

def fibonacci():
    a, b = 0, 1
    while True:
        yield a
        a, b = b, a + b

